#include <bits/stdc++.h>
using namespace std;
int main(){long long n,k;scanf("%lld %lld",&n,&k);long long lo=1,hi=k,ans=1;while(lo<=hi){long long mid=(lo+hi)/2,cnt=0;for(long long i=1;i<=n;i++)cnt+=min(mid/i,n);if(cnt>=k){ans=mid;hi=mid-1;}else lo=mid+1;}printf("%lld\n",ans);}
